	createDummyFile("hello.txt", "Hello from the uploads directory!")
	createDummyFile("data.json", `{"name": "example", "version": 1.0}`)
	createDummyFile("image.png", "This would be binary image data in a real scenario.") // Content doesn't matter for MIME type inference

	// Register the handler for paths starting with "/files/"
	// The trailing slash is important for `strings.TrimPrefix` to work correctly.
	http.HandleFunc("/files/", serveUploadsHandler)

	fmt.Println("Server starting on :8080")
	fmt.Printf("Test with: curl http://localhost:8080/files/hello.txt\n")
	fmt.Printf("Test with: curl http://localhost:8080/files/data.json\n")
	fmt.Printf("Test with: curl -I http://localhost:8080/files/image.png (to check Content-Type)\n")

