// createDummyFile is a helper to create test files in the uploads directory.
func createDummyFile(filename, content string) {
	filePath := filepath.Join(uploadsDir, filename)
	if _, err := os.Stat(filePath); os.IsNotExist(err) {
		fmt.Printf("Creating dummy file: %s\n", filename)
		err = os.WriteFile(filePath, []byte(content), 0644) // 0644 grants read/write for owner, read for group/others
		if err != nil {
			fmt.Printf("Failed to create %s: %v\n", filename, err)
		}
	}
}